#include <iostream>
#include <string>
#include <vector>
#include <cmath>

// Abstract class — cannot be instantiated
class GameEntity {
protected:
    std::string name;
    int health;

public:
    GameEntity(std::string n, int h) : name(n), health(h) {}

    virtual ~GameEntity() {}

    // Pure virtual functions — must be implemented by derived classes
    virtual void attack(GameEntity& target) = 0;
    virtual void takeDamage(int damage) = 0;
    virtual void display() const = 0;

    // Concrete method — available to all derived classes
    bool isAlive() const { return health > 0; }
    std::string getName() const { return name; }
    int getHealth() const { return health; }

    // Protected method for derived classes
    void setHealth(int h) { health = h; }
};

// Concrete class — implements all pure virtual functions
class Player : public GameEntity {
private:
    int attackPower;
    int level;

public:
    Player(std::string n, int h, int a, int l) 
        : GameEntity(n, h), attackPower(a), level(l) {}

    void attack(GameEntity& target) override {
        int damage = attackPower + (level * 2);
        std::cout << name << " attacks " << target.getName() 
                  << " for " << damage << " damage!" << std::endl;
        target.takeDamage(damage);
    }

    void takeDamage(int damage) override {
        health -= damage;
        if (health < 0) health = 0;
        std::cout << name << " took " << damage << " damage! (" << health << " HP left)" << std::endl;
    }

    void display() const override {
        std::cout << "Player: " << name << " (Level: " << level 
                  << ", HP: " << health << ", ATK: " << attackPower << ")" << std::endl;
    }
};

class Monster : public GameEntity {
private:
    int attackPower;
    std::string type;

public:
    Monster(std::string n, int h, int a, std::string t) 
        : GameEntity(n, h), attackPower(a), type(t) {}

    void attack(GameEntity& target) override {
        int damage = attackPower + (std::rand() % 8);
        std::cout << type << " " << name << " attacks " << target.getName() 
                  << " for " << damage << " damage!" << std::endl;
        target.takeDamage(damage);
    }

    void takeDamage(int damage) override {
        health -= damage;
        if (health < 0) health = 0;
        std::cout << name << " took " << damage << " damage! (" << health << " HP left)" << std::endl;
    }

    void display() const override {
        std::cout << type << " " << name << " (HP: " << health 
                  << ", ATK: " << attackPower << ")" << std::endl;
    }
};

// Another concrete class
class Boss : public GameEntity {
private:
    int attackPower;
    std::string specialMove;
    int phase;

public:
    Boss(std::string n, int h, int a, std::string s) 
        : GameEntity(n, h), attackPower(a), specialMove(s), phase(1) {}

    void attack(GameEntity& target) override {
        int damage = attackPower + (phase * 5) + (std::rand() % 10);
        std::cout << name << " uses " << specialMove << " for " << damage << " damage!" << std::endl;
        target.takeDamage(damage);

        // Phase change
        if (health < 50 && phase == 1) {
            phase = 2;
            std::cout << "⚡ " << name << " enters Phase 2! ⚡" << std::endl;
        }
    }

    void takeDamage(int damage) override {
        health -= damage;
        if (health < 0) health = 0;
        std::cout << name << " took " << damage << " damage! (" << health << " HP left)" << std::endl;
    }

    void display() const override {
        std::cout << "Boss " << name << " (Phase: " << phase 
                  << ", HP: " << health << ", ATK: " << attackPower 
                  << ", Move: " << specialMove << ")" << std::endl;
    }
};

// Function that works with any GameEntity
void fight(GameEntity& attacker, GameEntity& defender) {
    std::cout << "\n=== Fight! ===" << std::endl;
    while (attacker.isAlive() && defender.isAlive()) {
        attacker.attack(defender);
        if (defender.isAlive()) {
            defender.attack(attacker);
        }
    }

    std::cout << "\n=== Result ===" << std::endl;
    std::cout << attacker.getName() << " is " << (attacker.isAlive() ? "alive" : "dead") << std::endl;
    std::cout << defender.getName() << " is " << (defender.isAlive() ? "alive" : "dead") << std::endl;
}

int main() {
    std::srand(std::time(0));

    std::cout << "=== Abstract Classes & Pure Virtual Functions ===" << std::endl;

    // Cannot instantiate abstract class
    // GameEntity entity("Entity", 100);  // ERROR!

    // Create concrete objects
    Player hero("Aragorn", 120, 20, 5);
    Monster goblin("Goblin", 40, 10, "Goblin");
    Boss dragon("Dragon", 150, 25, "Flame Breath");

    hero.display();
    goblin.display();
    dragon.display();

    // Polymorphic vector of GameEntity pointers
    std::vector<GameEntity*> entities = {&hero, &goblin, &dragon};

    std::cout << "\n=== All Entities ===" << std::endl;
    for (GameEntity* e : entities) {
        e->display();
    }

    // Fight!
    fight(hero, dragon);

    return 0;
}

