#include <iostream>
#include <string>

class Attackable {
protected:
    std::string name;
    int health;

public:
    Attackable(std::string n, int h) : name(n), health(h) {}

    virtual ~Attackable() {}

    virtual void attack(Attackable& target) = 0;
    virtual void takeDamage(int damage) = 0;

    virtual void display() const {
        std::cout << name << " (HP: " << health << ")" << std::endl;
    }

    bool isAlive() const { return health > 0; }
    std::string getName() const { return name; }
};

class Warrior : public Attackable {
private:
    int strength;

public:
    Warrior(std::string n, int h, int s) : Attackable(n, h), strength(s) {}

    void attack(Attackable& target) override {
        int damage = strength + 5;
        std::cout << name << " (Warrior) attacks " << target.getName() 
                  << " for " << damage << " damage!" << std::endl;
        target.takeDamage(damage);
    }

    void takeDamage(int damage) override {
        health -= damage;
        if (health < 0) health = 0;
        std::cout << name << " took " << damage << " damage!" << std::endl;
    }

    void display() const override {
        std::cout << "Warrior " << name << " (HP: " << health 
                  << ", Strength: " << strength << ")" << std::endl;
    }
};

class Mage : public Attackable {
private:
    int magicPower;

public:
    Mage(std::string n, int h, int m) : Attackable(n, h), magicPower(m) {}

    void attack(Attackable& target) override {
        int damage = magicPower + 10;
        std::cout << name << " (Mage) attacks " << target.getName() 
                  << " for " << damage << " damage!" << std::endl;
        target.takeDamage(damage);
    }

    void takeDamage(int damage) override {
        health -= damage;
        if (health < 0) health = 0;
        std::cout << name << " took " << damage << " damage!" << std::endl;
    }

    void display() const override {
        std::cout << "Mage " << name << " (HP: " << health 
                  << ", Magic: " << magicPower << ")" << std::endl;
    }
};

int main() {
    Warrior hero("Aragorn", 120, 25);
    Mage wizard("Gandalf", 90, 30);

    std::cout << "=== Initial Stats ===" << std::endl;
    hero.display();
    wizard.display();

    std::cout << "\n=== Battle! ===" << std::endl;
    while (hero.isAlive() && wizard.isAlive()) {
        hero.attack(wizard);
        if (wizard.isAlive()) {
            wizard.attack(hero);
        }
    }

    std::cout << "\n=== Final Stats ===" << std::endl;
    hero.display();
    wizard.display();

    return 0;
}
